queries.sparql:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPlatforms ?child ; p:hasTrain_Stations ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Train_Stations } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPlatforms ?child ; p:hasTrain_Stations ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Train_Stations } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?name2 WHERE {
  ?train_stations_platforms a :Train_Stations_Platforms .
  ?platforms a :Platforms .
  ?train_stations_platforms p:hasPlatforms ?platforms .
  ?train_stations a :Train_Stations .
  ?train_stations_platforms p:hasTrain_Stations ?train_stations .
  ?train_stations p:name ?name .
  ?platforms p:name ?name2 .
} }
}
